"use client";

import { useEffect, useState } from "react";
import { useWallet } from "@solana/wallet-adapter-react";
import { useConnection } from "@solana/wallet-adapter-react";
import { AlertTriangle, ExternalLink, X } from "lucide-react";

/**
 * Detects a network mismatch between the app (Devnet) and the connected wallet.
 * Phantom/Solflare expose their active cluster via `window.solana.connection.rpcEndpoint`
 * or we probe by checking if a transaction would use a different genesis block.
 *
 * Simpler heuristic: try to fetch the wallet's SOL balance from Devnet.
 * If it throws "invalid" or the wallet reports mainnet, show the banner.
 *
 * For the POC we use a straightforward probe: check if the wallet's
 * reported network matches "devnet" via the injected provider.
 */
export function NetworkWarning() {
    const { connected, publicKey } = useWallet();
    const { connection } = useConnection();
    const [mismatch, setMismatch] = useState(false);
    const [dismissed, setDismissed] = useState(false);

    useEffect(() => {
        if (!connected || !publicKey) {
            setMismatch(false);
            return;
        }

        // Probe: request the balance of the connected wallet from our Devnet RPC.
        // If the wallet is on mainnet its injected provider may reject devnet RPCs.
        // We also check navigator.solana / window.phantom for the active network.
        const checkNetwork = async () => {
            try {
                // Check the injected Phantom / Solflare provider's active network
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const phantom = (window as any)?.phantom?.solana;
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                const solflare = (window as any)?.solflare;

                // Phantom exposes `_network` on its provider object
                if (phantom?.isConnected && phantom?._network) {
                    const net: string = phantom._network;
                    if (!net.includes("devnet")) {
                        setMismatch(true);
                        return;
                    }
                }

                // Solflare check
                if (solflare?.isConnected && solflare?.network) {
                    const net: string = solflare.network;
                    if (!net.includes("devnet")) {
                        setMismatch(true);
                        return;
                    }
                }

                // Fallback: try fetching balance from devnet. If RPC endpoint mismatch
                // causes an unusual error, flag it. Otherwise assume we're fine.
                await connection.getBalance(publicKey);
                setMismatch(false);
            } catch {
                // Swallow — don't flag a mismatch on generic RPC errors
                setMismatch(false);
            }
        };

        checkNetwork();
    }, [connected, publicKey, connection]);

    if (!mismatch || dismissed) return null;

    return (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50 w-full max-w-lg px-4">
            <div className="bg-amber-500/10 border border-amber-500/40 backdrop-blur-xl rounded-2xl p-4 flex items-start gap-3 shadow-2xl">
                <AlertTriangle
                    size={18}
                    className="text-amber-400 shrink-0 mt-0.5"
                />
                <div className="flex-1 min-w-0">
                    <p className="text-amber-300 font-semibold text-sm">
                        Network mismatch — switch to Devnet
                    </p>
                    <p className="text-amber-200/70 text-xs mt-1 leading-relaxed">
                        SolStream runs on Solana Devnet. Your wallet is currently set to
                        Mainnet. Switch it to Devnet before signing any transactions.
                    </p>
                    <div className="flex flex-wrap gap-3 mt-3">
                        <a
                            href="https://phantom.app/blog/developer-settings"
                            target="_blank"
                            rel="noopener noreferrer"
                            className="inline-flex items-center gap-1 text-xs text-amber-300 hover:text-amber-200 underline"
                        >
                            Phantom: how to switch <ExternalLink size={10} />
                        </a>
                        <a
                            href="https://faucet.solana.com"
                            target="_blank"
                            rel="noopener noreferrer"
                            className="inline-flex items-center gap-1 text-xs text-amber-300 hover:text-amber-200 underline"
                        >
                            Get free Devnet SOL <ExternalLink size={10} />
                        </a>
                    </div>
                </div>
                <button
                    onClick={() => setDismissed(true)}
                    className="text-amber-400/60 hover:text-amber-300 shrink-0"
                    aria-label="Dismiss"
                >
                    <X size={16} />
                </button>
            </div>
        </div>
    );
}
